// Build human-readable action summary for Slack
const actions = $('Generate Plan ID').item.json.actions || [];
const plan_id = $('Generate Plan ID').item.json.plan_id;
const summary = $('Generate Plan ID').item.json.summary;

const actionLines = actions.slice(0, 5).map(a =>
  `• *${a.action_type.toUpperCase()}* — ${a.entity_name || a.entity_id} (${a.entity_level}) | Risk: ${a.risk} | ${a.rationale}`
).join('\n');

const moreCount = actions.length > 5 ? `\n_...and ${actions.length - 5} more actions_` : '';

return [{ json: { plan_id, summary, actionLines: actionLines + moreCount, action_count: actions.length } }];
